  ('social-worker-moex-07811', 'social-worker', 'social-worker-moex-099-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '家務分工的研究發現：丈夫負擔的家務遠較妻子少。男士則抗議指出，有些工作，例如開車，多是男性 從事，但並不列為家務範圍。他們質疑的是「家務」變項的：', '["信度（reliability）", "效度（validity）", "完整度（completeness）", "鑑別度（discriminability）"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:39+00:00", "source_pdf_sha1": "01a38a7597b2", "answer_pdf_sha1": "7b44c41cbb23", "source_family": "moex-gov-tw", "moex": {"exam_code": "099010", "c": "902", "s": "700", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作研究方法", "year": "099", "exam_name": "099年第一次醫事人員、中醫師、營養師、心理師、語言治療師、醫師分試、社會工作師", "original_question_number": 4, "answer_corrected": false, "flags": ["answer_missing"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
